# Event data
$eventData = @{
    "title" = "Event Title";
    "message" = "Event Message";
    "eventTime" = (Get-Date).ToUniversalTime().ToString("o");  # ISO 8601 format
    "node" = "Node Name";  # Replace with the target node name
    "eventType" = "Event Type";  # Replace with the event type
}

$url = "$baseURL/your-api-endpoint"  # Replace with the correct API endpoint

$headers = @{
    "Content-Type" = "application/json"
}

# Convert the event data to JSON
$eventJson = $eventData | ConvertTo-Json

# Send the POST request
$response = Invoke-RestMethod -Uri $url -Method Post -Credential $credential -Headers $headers -Body $eventJson


if ($response.StatusCode -eq 201) {
    Write-Host "Event created successfully."
} else {
    Write-Host "Failed to create the event. Status code: $($response.StatusCode)"
    Write-Host "Response content: $($response.Content)"
}

