$date = Get-Date


## Find all Services that Orion Uses
$SW_Services = Get-Service -DisplayName "*SolarWinds*"
$SW_Services += Get-Service -DisplayName "Message Queuing"
$SW_Services += Get-Service -DisplayName "Net.Tcp Port Sharing Service"


echo "<-----------------------Stopping Services------------------------------>"
echo "Running Stop-Service on all SolarWinds Services on $APE"
echo "Solarwinds Services found:"
foreach($Service in $SW_Services)
{
    $sn = $Service.DisplayName
    echo "$sn"
}


foreach($Service in $SW_Services)
{
    ## Check status of service
    $status= $Service | select -ExpandProperty status
    if ($status -eq "Running")
    {
        ## Stop service and wait up to 20 seconds for the service to stop
        Stop-Service $Service -erroraction stop
        do
        {
            $status= $Service | select -ExpandProperty status
            $displayname = $Service.DisplayName
            echo "$date -> $displayname is $status"
            Start-Sleep -s 1
            $counter++
        }
        until ($status -eq "Stopped" -OR $counter -gt 20)

        ## If service not stopped in 20 seconds, force stop the process
        if($counter -gt 20)
        {
            $servicename = $Service.ServiceName
            switch -Regex ($servicename)
            {
            "SWJobEngineSvc2" {Stop-Process -Name SWJobEngineSvc2 -Force; Break}
            "SWCollectorService" {Stop-Process -Name SolarWinds.Collector.Service -Force; Break}
            "SolarWindsSyslogService" {Stop-Process -Name SyslogService -Force; Break}
            "SolarWindsTrapService" {Stop-Process -Name SWTrapService -Force; Break}
            "OrionModuleEngine" {Stop-Process -Name SolarWinds.BusinessLayerHost* -Force; Break}
            "SolarWindsHighAvailability" {Stop-Process -Name SolarWinds.HighAvailability.Service -Force; Break}
            "SWInfoServiceSvcV3" {Stop-Process -Name SolarWinds.InformationService.ServiceV3 -Force; Break}
            "SolarWindsAgent64" {Stop-Process -Name SolarWinds.Agent.Service -Force; Break}
            "SolarWindsCortex" {Stop-Process -Name SolarWinds.ServiceHost.Process -Force; Break}
            "SolarWindsRecommendations" {Stop-Process -Name SolarWinds.Recommendations.Service -Force; Break}
            "SWSEUMAgentProxySvc" {Stop-Process -Name SolarWinds.SEUM.AgentProxy.Service -Force; Break}
            "SWSEUMAgentSvc" {Stop-Process -Name SolarWinds.SEUM.Agent.Service -Force; Break}
            "SWJMXBridgeSvc" {Stop-Process -Name jsl -Force; Break }
            "SolarWindsAdministration" {Stop-Process -Name SolarWinds.Administration -Force; Break}
            }
        }
    }
    Clear-Variable -Name counter
}


echo "<-----------------------Services Stopped------------------------------>"
echo ""


## Wait 5 seconds before starting services up again
Start-Sleep 5


echo "<-----------------------Starting Services------------------------------>"
foreach($Service in $SW_Services)
{
    $status= $Service | select -ExpandProperty status
    if ($status -eq "Stopped")
        {
            Start-Service $Service -erroraction Continue
            do
            {
                $status= $Service | select -ExpandProperty status
                $displayname = $Service.DisplayName
                echo "$date -> $displayname is $status"
                Start-Sleep -s 5
            }
            until ($status -eq "Running")
        }
}
