function check_UnManage_XML($node)
{
    #Param ([string]$server)
    #$node = $server.server
    LogWrite "Node=$node;Message=`"Checking XMLs`""

    $found = Get-ChildItem "D:\Orion\UnmanageUtility\Jobs\" -Include *.xml -Recurse | Select-String -Pattern $node

    if($found)
    {
        foreach($find in $found)
        {
            $filepath = $find.Path
            $filename = $find.Filename
            LogWrite "Found=$find"

            $replace = Get-Content $filepath | Select-String -Pattern $node

            if($replace.count -gt 1)
            {
                foreach($entry in $replace)
                {
                    (Get-Content $filepath) -replace $entry,'' | Set-Content $filepath
                }
            }
            else
            {
                (Get-Content $filepath) -replace $replace,'' | Set-Content $filepath
            }
        }
    }
    else
    {
        LogWrite "Node=$node;Message=`"Not found in any XMLs`""
    }
}

