# Function to parse and filter Prometheus metrics
function Parse-PrometheusMetrics {
    param (
        [string]$prometheusMetrics
    )

    $metrics = @{
        "2XX" = 0
        "3XX" = 0
        "4XX" = 0
        "5XX" = 0
    }
    $lines = $prometheusMetrics -split "`n"
    foreach ($line in $lines) {
        if ($line -notmatch "^#") { # Ignore comment lines
            $parts = $line -split " "
            if ($parts.Length -eq 2) {
                $nameAndLabels = $parts[0]
                $value = [double]$parts[1]

                # Extract the metric name and labels
                if ($nameAndLabels -match "^kong_http_status\{(.*)\}$") {
                    $labelsString = $matches[1]
                    $labels = @{}

                    foreach ($label in $labelsString -split ",") {
                        $labelParts = $label -split "="
                        if ($labelParts.Length -eq 2) {
                            $labels[$labelParts[0]] = $labelParts[1].Trim('"')
                        }
                    }

                    if ($labels["service"] -and $labels["code"]) {
                        $responseCode = [int]$labels["code"]

                        if ($responseCode -ge 200 -and $responseCode -lt 300) {
                            $metrics["2XX"] += $value
                        } elseif ($responseCode -ge 300 -and $responseCode -lt 400) {
                            $metrics["3XX"] += $value
                        } elseif ($responseCode -ge 400 -and $responseCode -lt 500) {
                            $metrics["4XX"] += $value
                        } elseif ($responseCode -ge 500 -and $responseCode -lt 600) {
                            $metrics["5XX"] += $value
                        }
                    }
                }
            }
        }
    }
    return $metrics
}

