   ) < 1
BEGIN
    PRINT 'User must have SELECT permission on [msdb] database granted to run diagnostic mode.' + @new_line;
    RETURN;
END;

/* Is SQL2016+ detected */
IF ((SELECT CAST(SERVERPROPERTY('ProductVersion') AS NVARCHAR(32))) > '13.0') SET @sql2016plus = 1;

/* OS */
SELECT @os_type = RIGHT(@@VERSION, LEN(@@VERSION)- 3 -CHARINDEX (' ON ', @@VERSION));
/* SQL edition */
SELECT @sql_edition = CAST(SERVERPROPERTY('Edition') AS NVARCHAR(128));
/* SQL version */
SELECT @sql_version = CAST(SERVERPROPERTY('ProductVersion') AS NVARCHAR(64));
/* SQL product level */
SELECT @product_level = CAST(SERVERPROPERTY('ProductLevel') AS NVARCHAR(16));
SELECT @product_update_level = CAST(SERVERPROPERTY('ProductUpdateLevel') AS NVARCHAR(16));

/* Delimiter for Linux is different */
SET @delimiter = '\';
IF OBJECT_ID( 'sys.dm_os_host_info', 'V') IS NOT NULL
    IF (SELECT host_platform FROM sys.dm_os_host_info) = 'Linux'
        SET @delimiter = '/';

/* run at Orion DB */
SET @sql = N'USE ' + QUOTENAME(@orion_db);
EXEC(@sql);

BEGIN TRY
    /* SQL Server diag is missing */

    /* Orion DB files diag */
    WITH files
    AS
    (
    SELECT SUBSTRING(mf.physical_name, 1, LEN(mf.physical_name) - CHARINDEX('\', REVERSE(mf.physical_name))) AS data_path,
           mf.type_desc,
           CAST(COUNT(*) AS NVARCHAR(8)) AS files_cnt
     FROM sys.master_files mf WITH (NOLOCK)
    WHERE mf.database_id = DB_ID(@orion_db)
    GROUP BY SUBSTRING(mf.physical_name, 1, LEN(mf.physical_name) - CHARINDEX('\', REVERSE(mf.physical_name))),
             mf.type_desc
    )
    SELECT @file_paths = @file_paths + f.data_path + ' | ' + f.type_desc + ' | ' + f.files_cnt + IIF(f.files_cnt = 1, ' file', ' files') + @new_line
      FROM files f
    ;

    /* IFI */
    IF @sql2016plus = 1
    BEGIN
        SET @sql = 'SELECT @ifi_enabled = IIF(dss.instant_file_initialization_enabled = ''Y'',1,0)
                      FROM sys.dm_server_services dss WITH (NOLOCK)
                     WHERE servicename LIKE ''SQL Server (%''';
        EXEC sp_executesql @sql, N'@ifi_enabled INT OUTPUT', @ifi_enabled = @ifi_enabled OUTPUT;
    END;

    /* tempdb */
    SELECT @physical_socket_cnt = COUNT(mn.memory_node_id)-1
      FROM  sys.dm_os_memory_nodes mn
    ;

SELECT @templog_size = mf.size/128,
           @templog_autogrowth = mf.growth/128
      FROM sys.master_files mf
     WHERE mf.database_id = 2
       AND mf.type = 1
    ;

    /* CTFP */
    SELECT @ctfp = CAST(value_in_use AS TINYINT)
      FROM sys.configurations cf
     WHERE cf.name = 'cost threshold for parallelism'
    ;

    /* MAXDOP */
    SELECT @maxdop = CAST(value_in_use AS TINYINT)
      FROM sys.configurations cf
     WHERE cf.name = 'max degree of parallelism'
    ;

    SET @recom_maxdop = @recom_tempdb_file_cnt;

    /* MAX server memory */
    SELECT @server_memory = CAST(value_in_use AS BIGINT)
      FROM sys.configurations cf
     WHERE cf.name = 'max server memory (MB)'
    ;

SELECT @total_server_memory = CAST(total_physical_memory_kb/1024 AS BIGINT)
      FROM sys.dm_os_sys_memory WITH (NOLOCK)
    ;
    SET @num_of_sql_threads = 256 + IIF(@logical_cpu_cnt/@physical_socket_cnt > 4, @logical_cpu_cnt/@physical_socket_cnt, 0) * 8;
    SET @os_reserved = IIF(@total_server_memory <= 16000, CAST(@total_server_memory*0.2 AS BIGINT), CAST(@total_server_memory*0.125 AS BIGINT));

    SET @recom_server_memory = ROUND((@total_server_memory - (@num_of_sql_threads * @thread_stack_size) - (1000 + CEILING(@logical_cpu_cnt/4)) - @os_reserved), -2);

    /* Oprimize for AdHoc Workloads */
    SELECT @opt_ad_hoc_workloads_enabled = CAST(value_in_use AS BIT)
      FROM sys.configurations cf
     WHERE cf.name = 'optimize for ad hoc workloads'
    ;

    /* Query Optimizer Fixes */
    IF @sql2016plus = 1
    BEGIN
        SELECT @query_optimizer_fixes_enabled = CAST(dsc.[value] AS BIT)
          FROM sys.database_scoped_configurations dsc
         WHERE dsc.[name] = 'QUERY_OPTIMIZER_HOTFIXES'
        ;
    END;

    /* Compatibility level */
    SELECT @compatibility_level = d.compatibility_level
      FROM sys.databases d
     WHERE d.database_id = DB_ID(@orion_db)
    ;

SELECT @last_full_backup = MAX(bcp.backup_start_date)
      FROM msdb.dbo.backupset bcp
     WHERE bcp.database_name = @orion_db
       AND bcp.type = 'D'
    ;

    IF (SELECT SERVERPROPERTY('EngineEdition')) != 8
    BEGIN
        /* DB mirroring */
        SELECT @db_mirroring_enabled = IIF(dm.mirroring_state IS NULL,0,1)
          FROM sys.database_mirroring dm WITH(NOLOCK)
         WHERE dm.database_id = DB_ID()
        ;

        /* Transaction Log Shipping */
        IF EXISTS (
                    SELECT ls.primary_database
                        FROM msdb.dbo.log_shipping_primary_databases ls
                        WHERE ls.primary_database = @orion_db
                  )
            SET @log_shipping_enabled = 1;
        ELSE
            SET @log_shipping_enabled = 0;

        /* Availability Groups */
        IF EXISTS (
                    SELECT adc.database_name
                      FROM sys.availability_databases_cluster adc
                     WHERE adc.database_name = @orion_db
                  )
            SET @availability_groups_enabled = 1;
        ELSE
            SET @availability_groups_enabled = 0;
    END;

/*****************************************************************************/
    /*                            Diagnostics OUTPUT                             */
    /*****************************************************************************/
    IF @diagnostics_hidden = 0
    BEGIN
        PRINT 'Server HW Configuration' + @new_line;
        PRINT '- - - - - - - - - - - -' + @new_line;
        PRINT 'Total RAM memory: ' + CAST(@total_server_memory AS NVARCHAR(32)) + @new_line;
        PRINT 'Logical CPUs: ' + CAST(@logical_cpu_cnt AS NVARCHAR(4)) + @new_line;
        PRINT 'CPU sockets: ' + CAST(@physical_socket_cnt AS NVARCHAR(4)) + @new_line;
        PRINT @line;
        PRINT 'SQL Server Details' + @new_line;
        PRINT '- - - - - - - - - ' + @new_line;
        PRINT 'Edition: ' + @sql_edition + @new_line;
        PRINT 'Version: ' + @sql_version + @new_line;
        PRINT 'Product Level: ' + @product_level + @new_line;
        PRINT 'Product Update Level: ' + @product_update_level + @new_line;
        PRINT 'OS: ' + @os_type + @new_line;
        PRINT @line;
        PRINT 'Orion DB Files' + @new_line;
        PRINT '- - - - - - - ' + @new_line;
        PRINT 'Please note that transaction log file (LOG) and data files (ROWS) should have been located at different and dedicated physical drives!' + @new_line;
        PRINT @file_paths;
        PRINT @line;
        IF @sql2016plus = 1
        BEGIN
            PRINT 'Instant File Initialization = ' + CAST(@ifi_enabled AS NVARCHAR(1)) + @new_line;
            IF @ifi_enabled = 0 PRINT 'Please add proper OS permissions to the user SQL Server service is running on.';
            PRINT @line;
        END;
        PRINT 'tempdb Configuration' + @new_line + @new_line;
        PRINT '- - - - - - - - - - - '
        PRINT 'tempdb Data File Count' + @new_line;
        PRINT 'Current value = ' + CAST(@tempdb_file_cnt AS NVARCHAR(2)) + @new_line;
        PRINT 'Recommended value = ' + CAST(@recom_tempdb_file_cnt AS NVARCHAR(2)) + @new_line;
        PRINT '- - - - - - - - - - - - - - - - - - '
        PRINT 'tempdb Data File Size and Autogrowth' + @new_line;
        IF @tempfile_dif_growth_cnt > 1 OR @tempfile_dif_size_cnt > 1
        BEGIN
            PRINT 'There are ' + CAST(@tempfile_dif_size_cnt AS NVARCHAR(3)) + ' different data file sizes and ' + CAST(@tempfile_dif_growth_cnt AS NVARCHAR(3)) + ' different autogrowth options used!' + @new_line;
            PRINT 'All tempdb data files should have same size and autogrowth to perform well.' + @new_line;
        END;
        PRINT '- - - - - ';
        PRINT 'Autogrowth';
        PRINT 'Current (max) value in MB = ' + CAST(@max_tempfile_autogrowth AS NVARCHAR(9));
        PRINT 'Recommended min value in MB = ' + CAST(@recom_tempfile_autogrowth AS NVARCHAR(9));
        PRINT '- - ';
        PRINT 'Size';
        PRINT 'Current (max) value in MB = ' + CAST(@max_tempfile_size AS NVARCHAR(9));
        PRINT 'Recommended min value in MB = ' + CAST(@recom_tempfile_size AS NVARCHAR(9));
        PRINT '- - - - - - - - - - - - - - - - - - - - - - - -';
        PRINT 'tempdb Transaction Log File Size and Autogrowth' + @new_line;
        PRINT '- - - - - ';
        PRINT 'Autogrowth';
        PRINT 'Current value in MB = ' + CAST(@templog_autogrowth AS NVARCHAR(9));
        PRINT 'Recommended min value in MB = ' + CAST(@recom_templog_autogrowth AS NVARCHAR(9));
        PRINT '- - ';
        PRINT 'Size';
        PRINT 'Current value in MB = ' + CAST(@templog_size AS NVARCHAR(9));
        PRINT 'Recommended min value in MB = ' + CAST(@recom_templog_size AS NVARCHAR(9));
        PRINT '- - - - - - - -';
        PRINT 'tempdb Location = ' + @tempdb_path;
        PRINT @line;
        PRINT 'Cost Threshold For Parallelism' + @new_line;
        PRINT 'Current value = ' + CAST(@ctfp AS NVARCHAR(4)) + @new_line;
        PRINT 'Recommended value = ' + CAST(@recom_ctfp AS NVARCHAR(4)) + @new_line;
        PRINT @line;
        PRINT 'Maximum Degree Of Parallelism' + @new_line;
        PRINT 'Current value = ' + CAST(@maxdop AS NVARCHAR(4)) + @new_line;
        PRINT 'Recommended value = ' + CAST(@recom_maxdop AS NVARCHAR(4)) + @new_line;
        PRINT @line;
        PRINT 'Maximum Server Memory' + @new_line;
        PRINT 'Current value = ' + CAST(@server_memory AS NVARCHAR(24)) + @new_line;
        PRINT 'Recommended value = ' + CAST(@recom_server_memory AS NVARCHAR(24)) + @new_line;
        PRINT @line;
        PRINT 'Optimize For AdHoc Workloads' + @new_line;
        PRINT 'Current value = ' + CAST(@opt_ad_hoc_workloads_enabled AS NVARCHAR(1)) + @new_line;
        PRINT 'Recommended value = ' + CAST(@recom_opt_ad_hoc_workloads_enabled AS NVARCHAR(1)) + @new_line;
        PRINT @line;
        IF @sql2016plus = 1
        BEGIN
            PRINT 'Query Optimizer Hotfixes' + @new_line;
            PRINT 'Current value = ' + CAST( @query_optimizer_fixes_enabled AS NVARCHAR(1)) + @new_line;
            PRINT 'Recommended value = ' + CAST( @recom_query_optimizer_fixes_enabled AS NVARCHAR(1)) + @new_line;
            PRINT @line;
        END;
        PRINT 'Compatibility Level' + @new_line;
        PRINT 'Current value = ' + CAST(@compatibility_level AS NVARCHAR(3)) + @new_line;
        PRINT 'Recommended value = ' + CAST(@recom_compatibility_level AS NVARCHAR(3)) + @new_line;
        PRINT @line;
        PRINT 'Recovery Model = ' + @recovery_model + @new_line;
        IF @recovery_model = 'FULL'
        BEGIN
            IF @last_log_backup IS NULL PRINT 'LOG backup was never performed! Create stored procedure and periodical job to backup the transaction log!';
            ELSE PRINT 'Last LOG backup performed on ' + CAST(@last_log_backup AS NVARCHAR(32));
        END;
        IF @last_full_backup IS NULL PRINT 'FULL backup was never performed! Create stored procedure and periodical job to backup your database!';
        ELSE PRINT 'Last FULL backup performed on ' + CAST(@last_full_backup AS NVARCHAR(32));
        PRINT @line;
        IF (SELECT SERVERPROPERTY('EngineEdition')) != 8
        BEGIN
            PRINT 'DB Mirroring = ' + CAST(@db_mirroring_enabled AS NVARCHAR(1)) + @new_line;
            IF @db_mirroring_enabled = 1 PRINT 'DB Mirroring is not supported in SWI products! This feature is replaced by Availablity Groups.'
            PRINT @line;
            PRINT 'Transaction Log Shipping = ' + CAST(@log_shipping_enabled AS NVARCHAR(1)) + @new_line;
            PRINT @line;
            PRINT 'Availability Groups = ' + CAST(@availability_groups_enabled AS NVARCHAR(1)) + @new_line;
            PRINT @line;
        END;
    END;

/******************************************************************************/
    IF @diagnostics_only = 0
    BEGIN
        /* reconfigure tempdb */
        DECLARE @autogrowth INTEGER;
        DECLARE @size INTEGER;

        /* data files for tempdb higher value is better */
        SET @autogrowth = IIF(@max_tempfile_autogrowth > @recom_tempfile_autogrowth,@max_tempfile_autogrowth,@recom_tempfile_autogrowth);
        SET @size = IIF(@max_tempfile_size > @recom_tempfile_size,@max_tempfile_size,@recom_tempfile_size);

        /* change existing data files to have same characteristics */
        IF (@tempfile_dif_size_cnt > 1 OR @tempfile_dif_growth_cnt > 1) OR (@max_tempfile_autogrowth < @recom_tempfile_autogrowth OR @max_tempfile_size < @recom_tempfile_size)
        BEGIN
            /* same settings 4ALL */
            SET @sql = '';
            SELECT @sql = @sql + 'ALTER DATABASE tempdb MODIFY FILE (NAME = ' + mf.name + ', SIZE = ' + CAST(@size AS NVARCHAR(9)) + 'MB, FILEGROWTH = ' + CAST(@autogrowth AS NVARCHAR(9)) + ' MB)' + @new_line
              FROM sys.master_files mf
             WHERE mf.database_id = 2
               AND mf.type = 0
               AND (mf.size < @size*128
                OR mf.growth < @autogrowth*128)
            ;
            EXEC(@sql);
        END;

        IF @tempdb_file_cnt < @recom_tempdb_file_cnt
        BEGIN
            /* generate missing files */
            BEGIN
                DECLARE @i INTEGER = @tempdb_file_cnt;
                WHILE @i < @recom_tempdb_file_cnt BEGIN
                    SET @i = @i + 1;
                    SET @sql = '
                                    ALTER DATABASE tempdb
                                    ADD FILE
                                    (
                                        NAME = temp' + CAST(@i AS NVARCHAR) + ',
                                        FILENAME = ''' + @tempdb_path + @delimiter + 'temp' + CAST(@i AS NVARCHAR) + '.ndf'',
                                        SIZE = ' + CAST(@size AS NVARCHAR(9)) + 'MB,
                                        FILEGROWTH = ' + CAST(@autogrowth AS NVARCHAR(9)) + 'MB
                                    )
                                ';
                    EXEC sp_executesql @sql;
                END;
            END;
        END;

        /* trans log file for tempdb higher value is better */
        SET @autogrowth = IIF(@templog_autogrowth > @recom_templog_autogrowth,@templog_autogrowth,@recom_templog_autogrowth);
        SET @size = IIF(@templog_size > @recom_templog_size,@templog_size,@recom_templog_size);

        /* change existing data files to have same characteristics */
        IF (@templog_autogrowth < @recom_templog_autogrowth OR @templog_size < @recom_templog_size)
        BEGIN
            /* same settings 4ALL */
            SET @sql = '';
            SELECT @sql = @sql + 'ALTER DATABASE tempdb MODIFY FILE (NAME = ' + mf.name + ', SIZE = ' + CAST(@size AS NVARCHAR(9)) + 'MB, FILEGROWTH = ' + CAST(@autogrowth AS NVARCHAR(9)) + ' MB)' + @new_line
              FROM sys.master_files mf
             WHERE mf.database_id = 2
               AND mf.type = 1
               AND (mf.size < @size*128
                OR mf.growth < @autogrowth*128)
            ;
            EXEC(@sql);
        END;

        /* reconfigure CTFP */
        IF @ctfp < @recom_ctfp
        BEGIN
            EXEC sp_configure 'show advanced options', 1;
            RECONFIGURE;
            EXEC sp_configure 'cost threshold for parallelism', @recom_ctfp;
            RECONFIGURE;
        END;

        /* reconfigure MAXDOP */
        IF @maxdop < @recom_maxdop OR @maxdop > @logical_cpu_cnt
        BEGIN
            EXEC sp_configure 'show advanced options', 1;
            RECONFIGURE;
            EXEC sp_configure 'max degree of parallelism', @recom_maxdop;
            RECONFIGURE;
        END;

        /* reconfigure memory */
        IF @server_memory >= @total_server_memory OR @server_memory < 0.8*@recom_server_memory
        BEGIN
            EXEC sp_configure 'show advanced options', 1;
            RECONFIGURE;
            EXEC sp_configure 'max server memory', @recom_server_memory;
            RECONFIGURE;
        END;

        /* reconfigure Optimize For AdHoc Workloads */
        IF @opt_ad_hoc_workloads_enabled != @recom_opt_ad_hoc_workloads_enabled
        BEGIN
            EXEC sp_configure 'show advanced options', 1;
            RECONFIGURE;
            EXEC sp_configure 'optimize for ad hoc workloads', @recom_opt_ad_hoc_workloads_enabled;
            RECONFIGURE;
        END;

        /* reconfigure Query Optimizer Hotfixes */
        IF @sql2016plus = 1
            BEGIN
                IF @query_optimizer_fixes_enabled != @recom_query_optimizer_fixes_enabled
                BEGIN
                    SET @sql = 'ALTER DATABASE SCOPED CONFIGURATION SET QUERY_OPTIMIZER_HOTFIXES = ON'
                    EXEC(@sql);
                END;
            END;

        /* Compatibility level */
        IF @compatibility_level < @recom_compatibility_level
        BEGIN
            SET @sql = 'ALTER DATABASE [' + @orion_db + '] SET COMPATIBILITY_LEVEL = ' + CAST(@recom_compatibility_level AS NVARCHAR(3));
            EXEC(@sql);
        END;
    END;
END TRY
BEGIN CATCH
    SELECT @error_message = ERROR_MESSAGE(), @error_severity = ERROR_SEVERITY(), @error_state = ERROR_STATE();
    RAISERROR (@error_message, @error_severity, @error_state) WITH NOWAIT;
END CATCH;

