function get-Retired_CI
{

    $server = 'XXX'
    $url = "https://${server}:8089/services/search/jobs/export"
    $splunk_usr = "YOUR_USERNAME"
    $splunk_pwd = ConvertTo-SecureString "YOUR_PASSWORD" -AsPlainText -Force
    $cred = New-Object System.Management.Automation.PSCredential($splunk_usr,$splunk_pwd)

    $search = "|inputlookup Reconcile_Decom.csv"
    $body = @{
    search = $search
    output_mode = "csv"
    earliest_time = "-5m"
    latest_time = "-1m"
        }

add-type @"
    using System.Net;
    using System.Security.Cryptography.X509Certificates;
    public class TrustAllCertsPolicy : ICertificatePolicy {
        public bool CheckValidationResult(
            ServicePoint srvPoint, X509Certificate certificate,
            WebRequest request, int certificateProblem) {
            return true;
        }
    }
"@
[System.Net.ServicePointManager]::CertificatePolicy = New-Object TrustAllCertsPolicy

    # This will allow for self-signed SSL certs to work
    [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12
    [System.Net.ServicePointManager]::ServerCertificateValidationCallback = { $true }
    $SearchResults = Invoke-RestMethod -Method Post -Uri $url -Credential $cred -Body $body -TimeoutSec 300 | ConvertFrom-Csv
    return $SearchResults
}

# Orion Connection details
$hostname_prod = "XXX"
$hostname_test = "XXX"
$username = "YOUR_USERNAME"
$Password = YOUR_PASSWORD
$swis_prod = Connect-Swis -Hostname $hostname_prod -Username $username -Password $password
$swis_test = Connect-Swis -Hostname $hostname_test -Username $username -Password $password

# Collecting Retired CI data of Ivanti Prod from splunk
$Retired= get-Retired_CI
# Pull hostname from retired_CI list
$R=$Retired.Server_Hostname

# Collecting Nodes list of Orion Prod from Orion SDK
$All_prod=Get-SwisData $swis_prod "SELECT Caption FROM Orion.Nodes"
# Comparing Retired_CI list and Orion.nodes list
$Del_prod=Compare-Object $All_prod $R -IncludeEqual -ExcludeDifferent | Where-Object { $_.SideIndicator -eq '==' } | Foreach-Object { $_.InputObject }
$Del_prod_count = $Del_prod.Count

# Collecting Nodes list of Orion Test from Orion SDK
$All_test=Get-SwisData $swis_test "SELECT Caption FROM Orion.Nodes"
# Comparing Retired_CI list and Orion.nodes list
$Del_test=Compare-Object $All_test $R -IncludeEqual -ExcludeDifferent | Where-Object { $_.SideIndicator -eq '==' } | Foreach-Object { $_.InputObject }
$Del_test_count = $Del_test.Count

# Removing node from Orion Prod
foreach($D in $Del_prod)
{
    $NodeUri = Get-SwisData $swis_prod "SELECT Uri FROM Orion.Nodes where caption like '$D'"

    if($NodeUri.Count -gt 1)
    {
        Foreach($uri in $NodeUri)
        {
            LogWrite "$get_date`t`tNode=$D; Message=`"Deleted from PROD.`""
            Remove-SwisObject $swis_prod -Uri $uri
            continue
        }
    }
    else
    {
        LogWrite "Node=$D; Message=`"Deleted from PROD.`""
        Remove-SwisObject $swis_prod -Uri $NodeUri
    }
}

# Removing node from Orion Test
foreach($D in $Del_test)
{
    $NodeUri = Get-SwisData $swis_test "SELECT Uri FROM Orion.Nodes where caption like '$D'"

    if($NodeUri.Count -gt 1)
    {
        Foreach($uri in $NodeUri)
        {
            LogWrite "Node=$D; Message=`"Deleted from TEST.`""
            Remove-SwisObject $swis_test -Uri $uri
            continue
        }
    }
    else
    {
        LogWrite "Node=$D; Message=`"Deleted from TEST.`""
        Remove-SwisObject $swis_test -Uri $NodeUri
    }
}

