﻿# Function to parse and filter Prometheus metrics
function Parse-PrometheusMetrics {
    param (
        [string]$prometheusMetrics
    )

    $metrics = @{}
    $lines = $prometheusMetrics -split "`n"
    foreach ($line in $lines) {
        if ($line -notmatch "^#") { # Ignore comment lines
            $parts = $line -split " "
            if ($parts.Length -eq 2) {
                $nameAndLabels = $parts[0]
                $value = [double]$parts[1]

                # Extract the metric name and labels
                if ($nameAndLabels -match "^kong_http_status\{(.*)\}$") {
                    $labelsString = $matches[1]
                    $labels = @{}

                    foreach ($label in $labelsString -split ",") {
                        $labelParts = $label -split "="
                        if ($labelParts.Length -eq 2) {
                            $labels[$labelParts[0]] = $labelParts[1].Trim('"')
                        }
                    }

                    if ($labels["service"] -and $labels["code"]) {
                        $service = $labels["service"]
                        $responseCode = [int]$labels["code"]

                        if (-not $metrics.ContainsKey($service)) {
                            $metrics[$service] = @{}
                        }

                        if (-not $metrics[$service].ContainsKey($responseCode)) {
                            $metrics[$service][$responseCode] = 0
                        }

                        $metrics[$service][$responseCode] += $value
                    }
                }
            }
        }
    }
    return $metrics
}

# Convert hashtable to a nested dictionary
function ConvertTo-Dictionary {
    param (
        [hashtable]$hashtable
    )

    $dictionary = New-Object 'System.Collections.Generic.Dictionary[[String],[Object]]'
    foreach ($key in $hashtable.Keys) {
        $value = $hashtable[$key]
        if ($value -is [hashtable]) {
            $value = ConvertTo-Dictionary -hashtable $value
        }
        $dictionary.Add($key, $value)
    }
    return $dictionary
}

