function Parse-PrometheusMetrics {
    param (
        [string]$prometheusMetrics
    )

    $metrics = @{}
    $lines = $prometheusMetrics -split "`n"
    foreach ($line in $lines) {
        if ($line -notmatch "^#") { # Ignore comment lines
            if ($line -match "\{(.+?)\}") {
                $labels = $matches[1]
                $parts = $line -split " "
                if ($parts.Length -eq 2) {
                    $name = $parts[0] -replace "\{.*", ""
                    $value = [double]$parts[1]
                    $metric = @{ name = $name; value = $value }

                    $labels -split "," | ForEach-Object {
                        $key, $val = $_ -split "="
                        $val = $val.Trim('"')
                        $metric[$key] = $val
                    }

                    $metrics += ,$metric
                }
            }
        }
    }
    return $metrics
}

