# Check servers in Orion that show up in Ivanti but not Orion
# Reasons can be that the server in Orion is still marked as "!!_PLEASE_ASSIGN_!!" and not "Pre-Prod or Production".
# If it is in Orion as ICMP and !!_PLEASE_ASSIGN_!! then the script will delete the node and re-add using SNMP or WMI.
# If the server doesn't exist in Orion the script will try adding using the correct ObjTyp (SNMP or WMI).
$serverlist = get-splunk-search-results

# Loop through the serverlist
Foreach($record in $serverlist)
{
    $hostname = ($record.server).Trim()
    $appcode = ($record.Application_Code).Trim()
    $appname = ($record.Application_Name).Trim()

    $get_date = (Get-Date).ToString('MM/dd/yyyy HH:mm:ss')
    echo "$get_date`tNode=$hostname; --- Start $hostname ---" | Out-File $tmp_LogfilePath -Append

    if(!$hostname)
    {
        LogWrite "Message=`"Hostname field is empty. No records to update`""
        Continue
    }
    LogWrite "---------Start $hostname----------"
    # Start checking the hostname from list pulled from SplunkSCH03.
    $output = check $hostname
    $ip = $output[1]

    # Check $hostname will return all info found in Orion about the node. We now use the Node Exists property to determine if we need to
    # remove the old node or just add a new one.
    if($output[11] -like "true")
    {
        # Log if the Type is already SNMP or WMI
        if($output[2] -like 'SNMP' -or $output[2] -like 'WMI')
        {
            $typ = $output[2]
            LogWrite "Node=$hostname;Message=`"Already in Orion as $typ`""

            # Check if AppCode, AppName or Environment custom properties are there.
            if(!$output[4] -or !$output[5] -or !$output[7])
            {
                LogWrite "Message=`"AppCode, Appname or Environment are empty. Launching update Custom Properties.`""
                $updatednodeid = Update_Cust_Prop $hostname $appcode $appname
                Logwrite "Node_URI=https://monitoring/Orion/NetPerfMon/NodeDetails.aspx?NetObject=N:$updatednodeid"
            }

            if($output[7] -like 'Pre-Prod')
            {
                $updatednodeid = Update_Environment $hostname
                LogWrite "Node=$hostname; Message=`"Switched from Pre-Prod to Production!`""
            }

            LogWrite "--- End $hostname ---"
            continue
        }
        elseif($output[2] -like 'ICMP')
        {
            $typ = $output[2]
            LogWrite "Message=`"$hostname in Orion as $typ. Start updating to WMI or SNMP or skip if Hostname is not UP* or WP*.`""

            if($hostname -notlike "UP*" -and $hostname -notlike "WP*")
            {
                LogWrite "Message=`"Node already in Orion as ICMP but hostname does not start with UP* or WP*. Manually check if ICMP is good.`""
