# -----------------------------------------------------------------------------
# QUERY SOLARWINDS - get all monitored node IPs via SWIS REST API
# -----------------------------------------------------------------------------
function Get-SWMonitoredIPs {
    Write-Log "Querying SolarWinds: $($Config.SwisServer):$($Config.SwisPort)..."

    if ([string]::IsNullOrEmpty($Config.SwisUser)) {
        Write-Log "SwisUser not configured. Skipping SW comparison." "WARN"
        return $null
    }

    # Trust all SSL certs (SW uses self-signed cert)
    if (-not ([System.Management.Automation.PSTypeName]'TrustAll').Type) {
        Add-Type -TypeDefinition @'
using System.Net;
using System.Security.Cryptography.X509Certificates;
public class TrustAll : ICertificatePolicy {
    public bool CheckValidationResult(ServicePoint sp, X509Certificate cert, WebRequest req, int problem) {
        return true;
    }
}
'@
    }
    [System.Net.ServicePointManager]::CertificatePolicy = New-Object TrustAll
    [System.Net.ServicePointManager]::SecurityProtocol  = [System.Net.SecurityProtocolType]::Tls12

    $baseUrl  = "https://$($Config.SwisServer):$($Config.SwisPort)/SolarWinds/InformationService/v3/Json"
    $swql     = "SELECT NodeID, Caption, IPAddress, Status FROM Orion.Nodes ORDER BY Caption"
    $queryUrl = "$baseUrl/Query?query=$([Uri]::EscapeDataString($swql))"
    Write-Log "SWIS URL: $queryUrl"

    # Local SW account - must use Basic auth with base64 encoded credentials
    # PSCredential sends NTLM by default which doesn't work for local SW accounts
    $cred    = [Convert]::ToBase64String(
                   [Text.Encoding]::UTF8.GetBytes("$($Config.SwisUser):$($Config.SwisPass)")
               )
    $headers = @{
        "Authorization" = "Basic $cred"
        "Content-Type"  = "application/json"
    }

    try {
        $response = Invoke-RestMethod -Uri $queryUrl `
                    -Headers $headers `
                    -Method GET `
                    -UseBasicParsing `
                    -ErrorAction Stop

        $nodes = $response.results
        Write-Log "SolarWinds returned $($nodes.Count) nodes." "SUCCESS"
        return $nodes

    } catch {
        $code = $_.Exception.Response.StatusCode.value__
        Write-Log "SWIS API error (HTTP $code): $($_.Exception.Message)" "ERROR"
        if ($code -eq 403) { Write-Log "HTTP 403 - Account may lack Orion Read role in SW Admin." "ERROR" }
        if ($code -eq 401) { Write-Log "HTTP 401 - Wrong username or password." "ERROR" }
        return $null
    }
}

# -----------------------------------------------------------------------------
# COMPARE - find IPs that are Retired in CMDB but still monitored in SW
# -----------------------------------------------------------------------------
function Compare-RetiredCIsWithSW {
    param(
        [string]$CsvFile,
        $SwNodes
    )

    Write-Log "Comparing retired CMDB CIs with SolarWinds monitored nodes..."

    if (-not (Test-Path $Config.RetiredOutputDir)) {
        New-Item -ItemType Directory -Path $Config.RetiredOutputDir -Force | Out-Null
    }

    $cmdbData = Import-Csv -Path $CsvFile

    # Filter retired CIs with valid IP
    $retiredCIs = $cmdbData | Where-Object {
        $_.install_status -like "*Retired*" -and
        -not [string]::IsNullOrEmpty($_.ip_address)
    }
    Write-Log "Retired CIs in CMDB (with IP): $($retiredCIs.Count)"

    if ($retiredCIs.Count -eq 0) {
        $sample = ($cmdbData | Select-Object -First 5).install_status
        Write-Log "No retired CIs found. Sample install_status values: $($sample -join ', ')" "WARN"
        return
    }

    # Deduplicate CMDB retired IPs - keep one record per unique IP
    # When multiple CIs share the same IP, keep the most recently updated one
    $retiredByIP = @{}
    foreach ($ci in $retiredCIs) {
        $ip = $ci.ip_address.Trim()
        if (-not $retiredByIP.ContainsKey($ip)) {
            $retiredByIP[$ip] = $ci
        } else {
            # Keep the most recently updated CI for this IP
            try {
                $existingDate = [datetime]$retiredByIP[$ip].sys_updated_on
                $newDate      = [datetime]$ci.sys_updated_on
                if ($newDate -gt $existingDate) { $retiredByIP[$ip] = $ci }
            } catch {
                # If date parse fails keep existing
            }
        }
    }
    Write-Log "Unique retired IPs in CMDB: $($retiredByIP.Count) (was $($retiredCIs.Count) with dupes)"

    # Index SW nodes by IPAddress
    $swByIP = @{}
    foreach ($node in $SwNodes) {
        if (-not [string]::IsNullOrEmpty($node.IPAddress)) {
            $swByIP[$node.IPAddress.Trim()] = $node
        }
    }
    Write-Log "SolarWinds IPs indexed: $($swByIP.Count)"

    # Find matches - unique retired IP that is also in SW
    $matches = @()
    foreach ($ip in $retiredByIP.Keys) {
        if ($swByIP.ContainsKey($ip)) {
            $ci     = $retiredByIP[$ip]
            $swNode = $swByIP[$ip]
            $matches += [PSCustomObject]@{
                IP_Address         = $ip
                CMDB_CI_Name       = $ci.name
                CMDB_Class         = $ci.sys_class_name
                CMDB_InstallStatus = $ci.install_status
                CMDB_OpStatus      = $ci.operational_status
                CMDB_LastUpdated   = $ci.sys_updated_on
                SW_NodeID          = $swNode.NodeID
                SW_NodeName        = $swNode.Caption
                SW_Status          = switch ($swNode.Status) {
                                        1 { "Up" }
                                        2 { "Down" }
                                        3 { "Warning" }
                                        9 { "Unmanaged" }

