WHERE
(
  a.Vendor ='Cisco'
  AND (
  a.Status=2
  OR
  (a.Status=1 AND a.AvgResponseTime > 500)
  OR
  (a.Status=1 AND a.CPULoad > 85)
  OR
  (a.Status=1 AND a.PercentMemoryUsed > 85)
  OR
  (a.Status=1 AND g.HWStatusID > 3)
  OR
  (a.Status=1 AND a.PercentLoss > 10)
  )
)
) AS t1
-- ORDER BY APri DESC
ORDER BY
 CASE
   WHEN  t1.wConn = 1000 THEN 1000
   ELSE  Round((t1.wTime*1.0 + t1.PacketLoss*1.0 + t1.wCPU*1.0 + t1.wMemory*1.0 + t1.wHW*1.0),1)
 END DESC

----------------------
--  Legend
--
-- CON: Connection Status (Ping) (Red: Down, Green: Up)
-- ssh: Telnet link (Click-able,  a SSH client will open, providing you have installed SSH Client)
-- NODENAME: 	Node name 	(Click NODENAME to open Node Details Page)
-- RT: 	Response Time (Ping reply) >500ms: Warning, >1000ms: Critical,
-- MSEC: 	Response time in milliseconds
-- PL: 	Packet Loss (> 10%: Warning, >30%: Critical, =100%: Down)
-- PacketLoss: 	Packet Loss Percentage
-- CPU: 	CPU Status (>95%: Warning, >98%: Critical, =100%: Down)
-- CLOAD: 	CPU load percentage
-- Memory: 	Memory Status (>95%: Warning, >98%: Critical, =100%: Down)
-- RLOAD: 	Memory load percentage
-- HW: 	Worst hardware status
-- HWSTAT: 	Worst hardware status message (Click HWSTAT to open Node Hardware Details Page)
-- APri:  Alert priority


-- Nodes Down Duration
SELECT
n.Caption AS [Device]
,'/Orion/images/StatusIcons/Small-' + n.StatusIcon AS [_IconFor_Device]
,n.DetailsUrl AS [_LinkFor_Device]
,CONCAT(SUBSTRING(tostring(MAX(e.EVENTTIME)),1,4),SUBSTRING(tostring(MAX(e.EVENTTIME)),5,2),
        SUBSTRING(tostring(tolocal(MAX(e.EVENTTIME))),12,8)) as Downtime,
  CONCAT(HOURDIFF(tolocal(max(e.eventtime)),getdate())/24,' Day(s) ',
        HOURDIFF(tolocal(max(e.eventtime)),getdate())-(HOURDIFF(tolocal(max(e.eventtime)),getdate())/24)*24,'h ',
        MINUTEDIFF(tolocal(max(e.eventtime)),getdate())   -   (MINUTEDIFF(tolocal(max(e.eventtime)),getdate())/60)*60,'m') AS Duration
FROM Orion.Nodes n
INNER JOIN Orion.Events e ON n.NodeID = e.NetworkNode
WHERE (STATUS = 2 and E.Eventtype=1) and n.Caption<>'Heartbeat_Solarwinds' --and nodes.customproperties.SystemsGrouping Like '%CPE%'
GROUP BY NodeName, StatusIcon, DetailsUrl
ORDER BY MINUTEDIFF(tolocal(MAX(E.EventTime)),getdate())  desc

