function Compare-RetiredCIsWithSW {
    param(
        [string]$CsvFile,
        $SwNodes
    )

    Write-Log "Comparing retired CMDB CIs with SolarWinds monitored nodes..."

    if (-not (Test-Path $Config.RetiredOutputDir)) {
        New-Item -ItemType Directory -Path $Config.RetiredOutputDir -Force | Out-Null
    }

    $cmdbData = Import-Csv -Path $CsvFile

    # Filter retired CIs with valid IP
    $retiredCIs = $cmdbData | Where-Object {
        $_.install_status -like "*Retired*" -and
        -not [string]::IsNullOrEmpty($_.ip_address)
    }
    Write-Log "Retired CIs in CMDB (with IP): $($retiredCIs.Count)"

    if ($retiredCIs.Count -eq 0) {
        $sample = ($cmdbData | Select-Object -First 5).install_status
        Write-Log "No retired CIs found. Sample install_status values: $($sample -join ', ')" "WARN"
        return
    }

    # Deduplicate CMDB retired IPs - keep one record per unique IP
    # When multiple CIs share the same IP, keep the most recently updated one
    $retiredByIP = @{}
    foreach ($ci in $retiredCIs) {
        $ip = $ci.ip_address.Trim()
        if (-not $retiredByIP.ContainsKey($ip)) {
            $retiredByIP[$ip] = $ci
        } else {
            # Keep the most recently updated CI for this IP
            try {
                $existingDate = [datetime]$retiredByIP[$ip].sys_updated_on
                $newDate      = [datetime]$ci.sys_updated_on
                if ($newDate -gt $existingDate) { $retiredByIP[$ip] = $ci }
            } catch {
                # If date parse fails keep existing
            }
        }
    }
    Write-Log "Unique retired IPs in CMDB: $($retiredByIP.Count) (was $($retiredCIs.Count) with dupes)"

    # Index SW nodes by IPAddress
    $swByIP = @{}
    foreach ($node in $SwNodes) {
        if (-not [string]::IsNullOrEmpty($node.IPAddress)) {
            $swByIP[$node.IPAddress.Trim()] = $node
        }
    }
    Write-Log "SolarWinds IPs indexed: $($swByIP.Count)"

    # Find matches - unique retired IP that is also in SW
    $matches = @()
    foreach ($ip in $retiredByIP.Keys) {
        if ($swByIP.ContainsKey($ip)) {
            $ci     = $retiredByIP[$ip]
            $swNode = $swByIP[$ip]
            $matches += [PSCustomObject]@{
                IP_Address         = $ip
                CMDB_CI_Name       = $ci.name
                CMDB_Class         = $ci.sys_class_name
                CMDB_InstallStatus = $ci.install_status
                CMDB_OpStatus      = $ci.operational_status
                CMDB_LastUpdated   = $ci.sys_updated_on
                SW_NodeID          = $swNode.NodeID
                SW_NodeName        = $swNode.Caption
                SW_Status          = switch ($swNode.Status) {
                                        1 { "Up" }
                                        2 { "Down" }
                                        3 { "Warning" }
                                        9 { "Unmanaged" }
                                        default { "Unknown ($($swNode.Status))" }
                                     }
            }
        }
    }

    # Sort by SW Status then IP for easy reading
    $matches = $matches | Sort-Object SW_Status, IP_Address

    Write-Log "Retired in CMDB AND monitored in SolarWinds: $($matches.Count)" "SUCCESS"

    if ($matches.Count -eq 0) {
        Write-Log "No overlap found - no retired CMDB CIs currently monitored in SW."
        return
    }

    # Export
    $dateStamp  = Get-Date -Format "yyyyMMdd_HHmmss"
    $reportFile = "$($Config.RetiredOutputDir)\Retired_Still_Monitored_$dateStamp.csv"
    $latestFile = "$($Config.RetiredOutputDir)\Retired_Still_Monitored_LATEST.csv"

    # Write timestamped file
    $matches | Export-Csv -Path $reportFile -NoTypeInformation -Force

    # Verify timestamped file exists before copying to LATEST
    if (Test-Path $reportFile) {
        # Remove old LATEST first to avoid lock issues
        if (Test-Path $latestFile) {
            Remove-Item -Path $latestFile -Force -ErrorAction SilentlyContinue
        }
        Copy-Item -Path $reportFile -Destination $latestFile -Force
        if (Test-Path $latestFile) {
            Write-Log "Report saved : $reportFile ($($matches.Count) unique IPs)" "SUCCESS"
            Write-Log "LATEST saved : $latestFile" "SUCCESS"
        } else {
            Write-Log "LATEST copy failed - writing directly instead." "WARN"
            $matches | Export-Csv -Path $latestFile -NoTypeInformation -Force
            Write-Log "LATEST saved (direct write): $latestFile" "SUCCESS"
        }
    } else {
        Write-Log "Timestamped file not found after Export-Csv - writing both directly." "WARN"
        $matches | Export-Csv -Path $reportFile -NoTypeInformation -Force
        $matches | Export-Csv -Path $latestFile -NoTypeInformation -Force
        Write-Log "Both files written directly." "SUCCESS"
    }

    # Console summary
    Write-Host ""
    Write-Host "  ============================================" -ForegroundColor Red
    Write-Host "  RETIRED IN CMDB - STILL MONITORED IN SW" -ForegroundColor Red
    Write-Host "  ============================================" -ForegroundColor Red
    Write-Host "  Total unique IPs: $($matches.Count)" -ForegroundColor Yellow
    Write-Host ""
    $matches | Format-Table IP_Address, CMDB_CI_Name, SW_NodeName, SW_Status -AutoSize
    Write-Host ""

    return $reportFile
}
