function Stop-Chrome {
    if (-not $script:ChromePID) {
        Write-Log "No tracked Chrome PID."
        return
    }

    # Just minimize Chrome window - do NOT kill it
    # Killing Chrome was closing ISE due to Windows job object inheritance
    try {
        $shell = New-Object -ComObject Shell.Application
        $shell.MinimizeAll()
        Write-Log "Chrome minimized (PID $($script:ChromePID)). You can close it manually." "SUCCESS"
    } catch {
        Write-Log "Could not minimize Chrome: $($_.Exception.Message)" "WARN"
    }

    # We intentionally do NOT kill Chrome here
    # Cookies are now saved - next run will skip Chrome entirely
    $script:ChromePID = $null
}

