function Test-SessionValid {
    param([string]$CookieHeader)
    # Test using SN navigation page - not REST API
    # REST API requires snc_platform_rest_api_access role which cookies may not provide
    # navpage.do just needs a valid SN browser session
    $testUrl = "$($Config.SNInstance)/navpage.do"
    $headers = @{
        "Cookie"     = $CookieHeader
        "Accept"     = "text/html"
        "User-Agent" = "Mozilla/5.0 (Windows NT 10.0; Win64; x64)"
    }
    try {
        $r = Invoke-WebRequest -Uri $testUrl -Headers $headers `
             -UseBasicParsing -MaximumRedirection 0 -ErrorAction Stop
        if ($r.StatusCode -eq 200) {
            Write-Log "Session VALID (navpage.do returned 200)." "SUCCESS"
            return $true
        }
    } catch {
        $code = $_.Exception.Response.StatusCode.value__
        if ($code -eq 302) {
            # 302 redirect to Okta = session expired
            Write-Log "Session expired - redirecting to Okta (HTTP 302)." "WARN"
        } elseif ($code -eq 401) {
            Write-Log "Session invalid (HTTP 401)." "WARN"
        } else {
            Write-Log "Session check returned HTTP $code." "WARN"
        }
    }
    return $false
}

# -----------------------------------------------------------------------------
# LAUNCH CHROME WITH CDP
# Opens SN report URL directly - Chrome+Okta profile handles SSO automatically
# -----------------------------------------------------------------------------

function Wait-ForSNPageLoad {
    Write-Log "Waiting for ServiceNow to load (max $($Config.PageLoadTimeoutSec)s)..."
    Write-Host ""
    Write-Host "  ================================================" -ForegroundColor Yellow
    Write-Host "  Chrome is opening ServiceNow..." -ForegroundColor White
    Write-Host "  - If Okta session is active: loads automatically" -ForegroundColor Green
    Write-Host "  - If Okta session expired: log in when prompted" -ForegroundColor Yellow
    Write-Host "  Script continues once SN home page is detected." -ForegroundColor White
    Write-Host "  ================================================" -ForegroundColor Yellow
    Write-Host ""

    $cdpBase  = "http://localhost:$($Config.ChromePort)"
    $deadline = (Get-Date).AddSeconds($Config.PageLoadTimeoutSec)
    $stableUrls = @{}   # tabId -> url (for stability check)

    while ((Get-Date) -lt $deadline) {
        try {
            $tabs = Invoke-RestMethod -Uri "$cdpBase/json" -ErrorAction Stop

            foreach ($tab in ($tabs | Where-Object { $_.type -eq "page" })) {
                $url = $tab.url
                if ([string]::IsNullOrEmpty($url)) { continue }

                # ---- STILL IN REDIRECT CHAIN - skip and keep waiting ----------
                # These are all intermediate URLs - not ready yet
                $inRedirect = (
                    $url -like "*auth_redirect.do*"  -or   # SN SAML handler
                    $url -like "*SAMLRequest*"        -or   # SAML outbound
                    $url -like "*SAMLResponse*"       -or   # SAML inbound
                    $url -like "*stateToken*"         -or   # Okta state
                    $url -like "*login/token/redirect*"     # Okta token redirect
                )
                if ($inRedirect) {
                    Write-Host "    SSO in progress... ${url.Substring(0, [Math]::Min(60,$url.Length))}" -ForegroundColor DarkGray
                    $stableUrls.Remove($tab.id)   # reset stability for this tab
                    continue
                }

                # ---- OKTA APP HOME - navigate directly to SN -----------------
                # This happens when Okta session was active but opened Okta first
                if ($url -like "*okta.com/app/UserHome*" -or
                    $url -like "*okta.com/app/YOUR_COMPANY*") {
                    Write-Log "Okta UserHome detected - navigating to ServiceNow directly..." "WARN"
                    # Use CDP to navigate this tab to SN
                    $navigated = Invoke-CDPNavigate -TabId $tab.id -TargetUrl $Config.SNInstance
                    if ($navigated) {
                        Write-Log "Navigated Chrome tab to ServiceNow." "SUCCESS"
                    }
                    $stableUrls.Remove($tab.id)
                    continue
                }

                # ---- SERVICENOW LOADED - check stability ---------------------
                if ($url -like "*YOUR_SERVER_HOSTNAME*") {
                    $prev = $stableUrls[$tab.id]

                    if ($prev -eq $url) {
                        # Same URL two polls in a row = page has settled
                        Write-Log "ServiceNow stable: $url" "SUCCESS"
                        Start-Sleep -Seconds 3   # let all cookies finalize
                        return $tab.id
                    } else {
                        $stableUrls[$tab.id] = $url
                        $short = $url.Substring(0, [Math]::Min(80, $url.Length))
                        Write-Host "    SN loading: $short" -ForegroundColor DarkGreen
                    }
                }
            }
        } catch {
            Write-Host "    CDP not ready yet... retrying" -ForegroundColor DarkGray
        }

        $remaining = [math]::Max(0, [int]($deadline - (Get-Date)).TotalSeconds)
        Write-Host "    Waiting... ${remaining}s remaining" -ForegroundColor Gray
        Start-Sleep -Seconds $Config.PollIntervalSec
    }

    Write-Log "Timeout waiting for ServiceNow to load!" "ERROR"
    return $null
}

# -----------------------------------------------------------------------------
# CDP NAVIGATE - push a Chrome tab to a specific URL
# -----------------------------------------------------------------------------

# CDP WebSocket helper - .NET 4.x compatible (works in PS2EXE)
# Uses inline C# to implement minimal WebSocket framing without System.Net.WebSockets
if (-not ([System.Management.Automation.PSTypeName]'CDPHelper').Type) {
    Add-Type -Language CSharp -TypeDefinition @"
using System;
using System.IO;
using System.Net.Sockets;
using System.Text;
using System.Net;
public class CDPHelper {
    public static string SendCommand(string wsUrl, string jsonCmd) {
        Uri uri = new Uri(wsUrl.Replace("ws://", "http://"));
        string host = uri.Host;
        int port = uri.Port > 0 ? uri.Port : 80;
        string path = uri.PathAndQuery;
        TcpClient tcp = new TcpClient();
        tcp.Connect(host, port);
        NetworkStream ns = tcp.GetStream();
        string key = Convert.ToBase64String(Guid.NewGuid().ToByteArray());
        string hs = "GET " + path + " HTTP/1.1\r\n"
                  + "Host: " + host + ":" + port + "\r\n"
                  + "Upgrade: websocket\r\n"
                  + "Connection: Upgrade\r\n"
                  + "Sec-WebSocket-Key: " + key + "\r\n"
                  + "Sec-WebSocket-Version: 13\r\n\r\n";
        byte[] hsb = Encoding.UTF8.GetBytes(hs);
        ns.Write(hsb, 0, hsb.Length);
        byte[] hbuf = new byte[4096];
        int hn = ns.Read(hbuf, 0, hbuf.Length);
        string hr = Encoding.UTF8.GetString(hbuf, 0, hn);
        if (!hr.Contains("101")) { tcp.Close(); return "ERROR:" + hr; }
        byte[] pl = Encoding.UTF8.GetBytes(jsonCmd);
        byte[] mk = new byte[]{ 0x12, 0x34, 0x56, 0x78 };
        int plen = pl.Length;
        byte[] fr;
        if (plen <= 125) {
            fr = new byte[6+plen]; fr[0]=0x81; fr[1]=(byte)(0x80|plen);
            Buffer.BlockCopy(mk,0,fr,2,4);
            for(int i=0;i<plen;i++) fr[6+i]=(byte)(pl[i]^mk[i%4]);
        } else {
            fr = new byte[8+plen]; fr[0]=0x81; fr[1]=(byte)(0x80|126);
            fr[2]=(byte)(plen>>8); fr[3]=(byte)(plen&0xFF);
            Buffer.BlockCopy(mk,0,fr,4,4);
            for(int i=0;i<plen;i++) fr[8+i]=(byte)(pl[i]^mk[i%4]);
        }
        ns.Write(fr, 0, fr.Length);
        MemoryStream ms = new MemoryStream();
        byte[] rb = new byte[131072];
        ns.ReadTimeout = 15000;
        try {
            while(true) {
                int r = ns.Read(rb,0,rb.Length);
                if(r==0) break;
                int hl=2, ml=rb[1]&0x7F;
                if(ml==126){ml=(rb[2]<<8)|rb[3];hl=4;}
                ms.Write(rb,hl,Math.Min(r-hl,ml));
                if(ms.Length>=ml) break;
            }
        } catch {}
        tcp.Close();
        return Encoding.UTF8.GetString(ms.ToArray());
    }
}
"@
}

