    $cutoff = (Get-Date).AddDays(-$Config.RetainDays)

    # Archive old CMDB files
    $old = Get-ChildItem -Path $Config.OutputDir -Filter "CMDB_Network_CIs_2*.csv" -ErrorAction SilentlyContinue |
           Where-Object { $_.LastWriteTime -lt $cutoff }
    foreach ($f in $old) {
        Move-Item $f.FullName "$($Config.ArchiveDir)\$($f.Name)" -Force
        Write-Log "Archived CMDB: $($f.Name)"
    }
    if ($old.Count -gt 0) { Write-Log "Cleanup: $($old.Count) CMDB files archived." }

    # Keep only latest N retired reports - delete older timestamped ones
    # Always keep LATEST file, only clean up timestamped files
    if (Test-Path $Config.RetiredOutputDir) {
        $retiredFiles = Get-ChildItem -Path $Config.RetiredOutputDir `
                        -Filter "Retired_Still_Monitored_2*.csv" `
                        -ErrorAction SilentlyContinue |
                        Sort-Object LastWriteTime -Descending

        # Keep only the 2 most recent timestamped files, delete the rest
        $keepCount = 2
        if ($retiredFiles.Count -gt $keepCount) {
            $toDelete = $retiredFiles | Select-Object -Skip $keepCount
            foreach ($f in $toDelete) {
                Remove-Item $f.FullName -Force -ErrorAction SilentlyContinue
                Write-Log "Deleted old retired report: $($f.Name)"
            }
            Write-Log "Retired folder cleanup: kept $keepCount, deleted $($toDelete.Count) old files."
        }
    }
}

