# -----------------------------------------------------------------------------
# LAUNCH CHROME WITH CDP
# Opens SN report URL directly - Chrome+Okta profile handles SSO automatically
# -----------------------------------------------------------------------------

function Wait-ForSNPageLoad {
    Write-Log "Waiting for ServiceNow to load (max $($Config.PageLoadTimeoutSec)s)..."
    Write-Host ""
    Write-Host "  ================================================" -ForegroundColor Yellow
    Write-Host "  Chrome is opening ServiceNow..." -ForegroundColor White
    Write-Host "  - If Okta session is active: loads automatically" -ForegroundColor Green
    Write-Host "  - If Okta session expired: log in when prompted" -ForegroundColor Yellow
    Write-Host "  Script continues once SN home page is detected." -ForegroundColor White
    Write-Host "  ================================================" -ForegroundColor Yellow
    Write-Host ""

    $cdpBase  = "http://localhost:$($Config.ChromePort)"
    $deadline = (Get-Date).AddSeconds($Config.PageLoadTimeoutSec)
    $stableUrls = @{}   # tabId -> url (for stability check)

    while ((Get-Date) -lt $deadline) {
        try {
            $tabs = Invoke-RestMethod -Uri "$cdpBase/json" -ErrorAction Stop

            foreach ($tab in ($tabs | Where-Object { $_.type -eq "page" })) {
                $url = $tab.url
                if ([string]::IsNullOrEmpty($url)) { continue }

                # ---- STILL IN REDIRECT CHAIN - skip and keep waiting ----------
                # These are all intermediate URLs - not ready yet
                $inRedirect = (
                    $url -like "*auth_redirect.do*"  -or   # SN SAML handler
                    $url -like "*SAMLRequest*"        -or   # SAML outbound
                    $url -like "*SAMLResponse*"       -or   # SAML inbound
                    $url -like "*stateToken*"         -or   # Okta state
                    $url -like "*login/token/redirect*"     # Okta token redirect
                )
                if ($inRedirect) {
                    Write-Host "    SSO in progress... ${url.Substring(0, [Math]::Min(60,$url.Length))}" -ForegroundColor DarkGray
                    $stableUrls.Remove($tab.id)   # reset stability for this tab
                    continue
                }

                # ---- OKTA APP HOME - navigate directly to SN -----------------
                # This happens when Okta session was active but opened Okta first
                if ($url -like "*okta.com/app/UserHome*" -or
                    $url -like "*okta.com/app/YOUR_COMPANY*") {
                    Write-Log "Okta UserHome detected - navigating to ServiceNow directly..." "WARN"
                    # Use CDP to navigate this tab to SN
                    $navigated = Invoke-CDPNavigate -TabId $tab.id -TargetUrl $Config.SNInstance
                    if ($navigated) {
                        Write-Log "Navigated Chrome tab to ServiceNow." "SUCCESS"
                    }
                    $stableUrls.Remove($tab.id)
                    continue
                }

                # ---- SERVICENOW LOADED - check stability ---------------------
                if ($url -like "*YOUR_SERVER_HOSTNAME*") {
                    $prev = $stableUrls[$tab.id]

                    if ($prev -eq $url) {
                        # Same URL two polls in a row = page has settled
                        Write-Log "ServiceNow stable: $url" "SUCCESS"
                        Start-Sleep -Seconds 3   # let all cookies finalize
                        return $tab.id
                    } else {
                        $stableUrls[$tab.id] = $url
                        $short = $url.Substring(0, [Math]::Min(80, $url.Length))
                        Write-Host "    SN loading: $short" -ForegroundColor DarkGreen
                    }
                }
            }
        } catch {
            Write-Host "    CDP not ready yet... retrying" -ForegroundColor DarkGray
        }

        $remaining = [math]::Max(0, [int]($deadline - (Get-Date)).TotalSeconds)
        Write-Host "    Waiting... ${remaining}s remaining" -ForegroundColor Gray
        Start-Sleep -Seconds $Config.PollIntervalSec
    }

    Write-Log "Timeout waiting for ServiceNow to load!" "ERROR"
    return $null
}

