Write-Log "============================================================"
Write-Log "SN CMDB Auto-Download START - $(Get-Date)"
Write-Log "============================================================"

Initialize-Dirs

$cookieHeader = $null
$authMethod   = "SavedCookies"

# ------------------------------------------------------------------
# STEP 1: Try saved cookies first (avoids Chrome entirely if valid)
# ------------------------------------------------------------------
$saved = Get-SavedCookies
if ($saved) {
    $cookieHeader = Build-CookieHeader -CookieJson $saved
    if (-not (Test-SessionValid -CookieHeader $cookieHeader)) {
        Write-Log "Saved cookies expired - will use Chrome to refresh." "WARN"
        $cookieHeader = $null
    }
}

# ------------------------------------------------------------------
# STEP 2: If no valid session - use Chrome to get fresh cookies
# Chrome opens SN directly, handles Okta SSO automatically
# ------------------------------------------------------------------
if (-not $cookieHeader) {
    $authMethod = "ChromeSSO"

    Start-ChromeWithCDP

    $tabId = Wait-ForSNPageLoad

    if (-not $tabId) {
        Write-Log "ServiceNow did not load in time. Exiting." "ERROR"
        Stop-Chrome
        exit 1
    }

    $cookies = Get-ChromeCookies -TabId $tabId

function Get-SWMonitoredIPs {
    Write-Log "Querying SolarWinds: $($Config.SwisServer)..."

    if ([string]::IsNullOrEmpty($Config.SwisUser)) {
        Write-Log "SwisUser not configured in Config. Skipping SW comparison." "WARN"
        return $null
    }

    $swisBase = "https://$($Config.SwisServer):$($Config.SwisPort)/SolarWinds/InformationService/v3/Json"

    # SWQL query - get all monitored nodes with their IPs
    $swql = "SELECT NodeID, Caption, IPAddress, Status FROM Orion.Nodes ORDER BY Caption"

    $queryUrl  = "$swisBase/Query?query=$([Uri]::EscapeDataString($swql))"
    $cred      = [Convert]::ToBase64String([Text.Encoding]::ASCII.GetBytes("$($Config.SwisUser):$($Config.SwisPass)"))
    $headers   = @{
        "Authorization" = "Basic $cred"
        "Content-Type"  = "application/json"
    }

    try {
        # Ignore SSL cert errors (common in internal SW installs)
        if (-not ([System.Management.Automation.PSTypeName]'TrustAll').Type) {
            Add-Type -TypeDefinition @'
using System.Net;
using System.Security.Cryptography.X509Certificates;
public class TrustAll : ICertificatePolicy {
    public bool CheckValidationResult(ServicePoint sp, X509Certificate cert, WebRequest req, int problem) {
        return true;
    }
}
'@
        }
        [System.Net.ServicePointManager]::CertificatePolicy = New-Object TrustAll
        [System.Net.ServicePointManager]::SecurityProtocol  = [System.Net.SecurityProtocolType]::Tls12

        $response = Invoke-RestMethod -Uri $queryUrl -Headers $headers `
                    -Method GET -UseBasicParsing -ErrorAction Stop

        $nodes = $response.results
        Write-Log "SolarWinds returned $($nodes.Count) monitored nodes." "SUCCESS"
        return $nodes

    } catch {
        Write-Log "SolarWinds API error: $($_.Exception.Message)" "ERROR"
        return $null
    }
}

