Function CleanUp_FQDN
{
    $query = "SELECT Caption,URI FROM Orion.Nodes Where (Caption like '%.com' or Caption like '%.unix') and Caption not like '%.YOUR_COMPANY.com'"
    $nodes = Get-SwisData -SwisConnection $swis -Query $query

    foreach ($node in $nodes)
    {
        if($node.Caption -like '*.unix.YOUR_COMPANY.com')
        {
         $newName = $node.Caption.Replace(".unix.YOUR_COMPANY.com","")
        }
        elseif($node.Caption -like '*.netops.YOUR_COMPANY.com')
        {
         $newName = $node.Caption.Replace(".netops.YOUR_COMPANY.com","")
        }
        elseif($node.Caption -like '*.ipt.YOUR_COMPANY.com')
        {
         $newName = $node.Caption.Replace(".ipt.YOUR_COMPANY.com","")
        }
        elseif($node.Caption -like '*prod-a.openshift.YOUR_COMPANY.com')
        {
         $newName = $node.Caption.Replace(".prod-a.openshift.YOUR_COMPANY.com","")
        }
        elseif($node.Caption -like '*.unix')
        {
         $newName = $node.Caption.Replace(".unix","")
        }
        elseif($node.Caption -like '*.YOUR_COMPANY.com')
        {
         $newName = $node.Caption.Replace(".YOUR_COMPANY.com","")
        }

        if ($node.Caption -ceq $newName)
        {
            continue
        }

    LogWrite "Message=`"Changing from $node to $newName`""
    Set-SwisObject -SwisConnection $swis -Uri $node.URI -Properties @{ "Caption" = $newName }
}

}

