Function Delete_Node([string]$hostname)
{
    $node_exists = Get-SwisData $swis "Select uri, NodeID, IP_Address,  ObjectSubType FROM Orion.Nodes where Caption like '$hostname'"
    $nodeId = $node_exists.NodeID
    $nodeuri = $node_exists.uri
    $nodeObjType = $node_exists.ObjectSubType
    #LogWrite "--- Sart Deleting Node ---"
    LogWrite "Node=$hostname;Message=`"Deleting $hostname`""

    # Run this if query returned results and Node already exists
    if($node_exists)
    {
        if($nodeObjType -eq 'ICMP')
        {
            Remove-SwisObject $swis -Uri $nodeuri
            LogWrite "Node=$hostname;Message=`"Already exists in Orion as NodeID ($nodeId). Deleting Node.`""
            #LogWrite "---------------------END DELETING NODE----------------------"
        }
        else
        {
            LogWrite "Node=$hostname;Message=`"Already configured as WMI`""
            #LogWrite "--------------------END----------------------"
            continue
        }
    }
}

