Function Update_Cust_Prop([string]$hostname,[string]$appcode,[string]$appname)
{
    #Parse out info from csv
    $devicetype = "Server"
    $entitytype = "Windows"
    $alerttemplate = "Windows Servers"
    $cpualert = "Global Windows (15)"
    $environment = "Production"

    #LogWrite "---------------------START UPDATING CUST PROP----------------------"
    #LogWrite "Node=$hostname"
    LogWrite "App_Code=$appcode"
    LogWrite "App_Name=$appname"

    $nodeid = Get-SwisData $swis "SELECT NodeID FROM Orion.Nodes where Caption = '$hostname'"
    LogWrite "NodeID=$nodeID"

    # Check Hostname and update Custom Properties depending on hostname
    if($hostname.StartsWith("SE")) {$entitytype = "branch"; $alerttemplate = "Branch Servers"; $cpualert = "Global Branch (60)"}
    if($hostname.StartsWith("U")) {$entitytype = "Unix"; $alerttemplate = "UNIX Servers"; $cpualert = "Global Unix (10)"}
    if($hostname.StartsWith("NO") -or $hostname.StartsWith("RO")){$entitytype = "SAN"; $alerttemplate = ""; $cpualert = "Network Infrastructure"; $devicetype = "ISILON"; $environment = "Production"}
    if($hostname.StartsWith("UD") -or $hostname.StartsWith("ud")) {$entitytype = "Unix"; $alerttemplate = "UNIX Servers"; $cpualert = "Global Unix (10)"; $environment = "Development"}
    $notes = "Updated by Orion_Auto on $logfiledate"

    # prepare a custom property value
    $customProps = @{
        DeviceType = $devicetype;
        Environment = $environment;
        Entity_Type = $entitytype;
        Alert_Template = $alerttemplate;
        Application_Code = $appcode;
        Application_Name = $appname;
        CPU_Alert = $cpualert;
        Notes = $notes;
    }

    $devtype = $customProps.DeviceType
    $envir = $customProps.Environment
    $et = $customProps.Entity_Type
    $at = $customProps.Alert_Template
    $ac = $customProps.Application_Code
    $an = $customProps.Application_Name
    $cpua = $customProps.CPU_Alert
    LogWrite "Message=`"Custom Properties to be added: DeviceType=$devtype; Environment=$envir; EntityType=$et; Alert_Template=$at; Application_Code=$ac; Application_Name=$an; CPU_Alert=$cpua; Caption=$hostname`""

    # build the node URI
    $uri_customprop = "swis://YOUR_SERVER_HOSTNAME.corp.YOUR_COMPANY.com/Orion/Orion.Nodes/NodeID=$($nodeId)/CustomProperties"
    $uri_main = "swis://YOUR_SERVER_HOSTNAME.corp.YOUR_COMPANY.com/Orion/Orion.Nodes/NodeID=$($nodeId)"
    LogWrite "Caption_URI=$uri_main"
    LogWrite "Custom_Prop_URI=$uri_customprop"

    # set the custom property
    Set-SwisObject $swis -Uri $uri_customprop -Properties $customProps

    #LogWrite "---------------------CUSTOM PROPERTIES UPDATED----------------------"
    return $nodeid
}

