Function clean_up_logfile
{
    Move-Item -Path $tmp_LogfilePath -Destination $LogfilePath
}
#endregion Functions

# This is where we run the different Functions depending on what we are doing
# Check servers in Orion that show up in Ivanti but not Orion
# Reasons can be that the server in Orion is still marked as "!!_PLEASE_ASSIGN_!!" and not "Pre-Prod or Production".
# If it is in Orion as ICMP and !!_PLEASE_ASSIGN_!! then the script will delete the node and re-add using SNMP or WMI.
# If the server doesn't exist in Orion the script will try adding using the correct ObjTyp (SNMP or WMI).
$serverlist = get-splunk-search-results

# Loop through the serverlist
Foreach($record in $serverlist)
{
    $hostname = ($record.server).Trim()
    $appcode = ($record.Application_Code).Trim()
    $appname = ($record.Application_Name).Trim()

    $get_date = (Get-Date).ToString('MM/dd/yyyy HH:mm:ss')
    echo "$get_date`tNode=$hostname; --- Start $hostname ---" | Out-File $tmp_LogfilePath -Append

    if(!$hostname)
    {
        LogWrite "Message=`"Hostname field is empty. No records to update`""
        Continue
    }
    LogWrite "---------Start $hostname----------"
    # Start checking the hostname from list pulled from SplunkSCH03.
    $output = check $hostname
    $ip = $output[1]

    # Check $hostname will return all info found in Orion about the node. We now use the Node Exists property to determine if we need to
    # remove the old node or just add a new one.
    if($output[11] -like "true")
    {
        # Log if the Type is already SNMP or WMI
        if($output[2] -like 'SNMP' -or $output[2] -like 'WMI')
        {
            $typ = $output[2]
            LogWrite "Node=$hostname;Message=`"Already in Orion as $typ`""

            # Check if AppCode, AppName or Environment custom properties are there.
            if(!$output[4] -or !$output[5] -or !$output[7])
            {
                LogWrite "Message=`"AppCode, Appname or Environment are empty. Launching update Custom Properties.`""
                $updatednodeid = Update_Cust_Prop $hostname $appcode $appname
                Logwrite "Node_URI=https://monitoring/Orion/NetPerfMon/NodeDetails.aspx?NetObject=N:$updatednodeid"
            }

            if($output[7] -like 'Pre-Prod')
            {
                $updatednodeid = Update_Environment $hostname
                LogWrite "Node=$hostname; Message=`"Switched from Pre-Prod to Production!`""
            }

            LogWrite "--- End $hostname ---"
            continue
        }
        elseif($output[2] -like 'ICMP')
        {
            $typ = $output[2]
            LogWrite "Message=`"$hostname in Orion as $typ. Start updating to WMI or SNMP or skip if Hostname is not UP* or WP*.`""

            if($hostname -notlike "UP*" -and $hostname -notlike "WP*")
            {
                LogWrite "Message=`"Node already in Orion as ICMP but hostname does not start with UP* or WP*. Manually check if ICMP is good.`""
                continue
            }

            #Launch Delete Node to remove existing ICMP Node. All details have been written to csv and $._
            if($output[3] -notlike "NoDelete")
            {
                Delete_Node $hostname
            }

            $node_exists = Get-SwisData $swis "Select uri, NodeID, IP_Address, ObjectSubType FROM Orion.Nodes where Caption like '$hostname'"
            if(!$node_exists)
            {
                LogWrite "Message=`"$hostname is new or has been removed. Checking Hostname for Windows or Unix.`""
                if($hostname -like "U*" -or $hostname -like "u*")
                {
                    $ip = $output[1]
                    LogWrite "Message=`"Adding $hostname as SNMPv3 using IP=$IP`""
                    Add_SNMPv3_Node $hostname $ip
                }
                elseif($hostname -like "W*" -or $hostname -like "w*" -or $hostname -like "*SQL*" -or $hostname -like "*sql*")
                {
                    $ip = $output[1]
                    LogWrite "Message=`"Adding $hostname as WMI using IP=$IP`""
                    Add_WMI_Node $hostname $ip
                }

            }
            else
            {
                Logwrite "Message=`"Node still exists or something went wrong.`""
                Continue
            }
        }

    }
    elseif($output[11] -like "false")
    {
        $typ = $output[2]
            LogWrite "Message=`"$hostname NOT in Orion. Adding as WMI or SNMP or ICMP.`""
            #LogWrite "-----------------------------------------------------------"

            if($hostname -like "U*" -or $hostname -like "u*")
            {
                $ip = $output[1]
                LogWrite "Message=`"Adding $hostname as SNMPv3 using IP=$IP`""
                Add_SNMPv3_Node $hostname $ip
            }
            elseif($hostname -like "W*" -or $hostname -like "w*" -or $hostname -like "*SQL*" -or $hostname -like "*sql*" -or $hostname -like "ROC*")
            {
                $ip = $output[1]
                LogWrite "Message=`"Adding $hostname as WMI using IP=$IP`""
                Add_WMI_Node $hostname $ip
            }
            else
            {
                $ip = $output[1]
                LogWrite "Message=`"Adding $hostname as ICMP using IP=$IP`""
                Add_ICMP_Node $hostname $ip
                LogWrite "Message=`"Node added as ICMP. Skipping second check. Manual check $hostname`""
                continue
            }
    }
    else
    {
        LogWrite "Message=`"IP=$ip already exists in some way. Check IP and hostname in Orion.`""
        #LogWrite "-----------end $hostname------------"
        Continue
    }

    #Check Node again for correct ObjTyp after re-adding is complete
    #LogWrite "------------STARTING SECOND CHECK AFTER RE-ADDING NODE----------"
    $new_node = Second_Check $ip

Function get-splunk-search-results
{

    $server = 'XXXX'
    $url = "https://${server}:8089/services/search/jobs/export"
    $splunk_usr = "YOUR_USERNAME"
    $splunk_pwd = ConvertTo-SecureString "YOUR_PASSWORD" -AsPlainText -Force
    $cred = New-Object System.Management.Automation.PSCredential($splunk_usr,$splunk_pwd)

    $search = "| inputlookup ivanti_not_orion.csv"
    $body = @{
    search = $search
    output_mode = "csv"
    earliest_time = "-5m"
    latest_time = "-1m"
        }

add-type @"
    using System.Net;
    using System.Security.Cryptography.X509Certificates;
    public class TrustAllCertsPolicy : ICertificatePolicy {
        public bool CheckValidationResult(
            ServicePoint srvPoint, X509Certificate certificate,
            WebRequest request, int certificateProblem) {
            return true;
        }
    }
"@
[System.Net.ServicePointManager]::CertificatePolicy = New-Object TrustAllCertsPolicy

    # This will allow for self-signed SSL certs to work
    [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12
    [System.Net.ServicePointManager]::ServerCertificateValidationCallback = { $true }
    $SearchResults = Invoke-RestMethod -Method Post -Uri $url -Credential $cred -Body $body -TimeoutSec 300 | ConvertFrom-Csv
    return $SearchResults
}

